      .submit-confirm-icon {
        display: flex;
        align-items: center;
        justify-content: center;
        width: 16px;
        height: 16px;
        border-radius: 50%;
        background: #f58f54;
        color: #ffffff;
        font-size: 12px;
        line-height: 1;
        font-weight: 700;
        font-family: 'Times New Roman', serif;
      }

      .submit-confirm-title {
        font-weight: 500;
        font-size: 16px;
        line-height: 100%;
        color: #1d2129;
      }
    }

    .submit-confirm-desc {
      display: flex;
      body[dir='ltr'] & {
        margin-left: 26px;
      }
      body[dir='rtl'] & {
        margin-right: 26px;
      }

      margin-bottom: 12px;
      font-size: 12px;
      font-weight: 400;
      font-size: 14px;
      line-height: 100%;
      color: #4e5969;
    }

    .submit-confirm-actions {
      display: flex;
      justify-content: end;
      gap: 8px;
    }
  }
}

