file.content:
.ratrol-record-detail {
  display: flex;
  flex-direction: column;
  width: 100%;
  height: 100%;
  background-color: #f2f3f5;
  overflow: hidden;

  // ── Page wrapper ──────────────────────────────────────────────────────────
  &__wrapper {
    flex: 1;
    overflow: hidden;
    display: flex;
    flex-direction: column;
    padding: 16px 20px 20px;
  }

  // ── Main card ─────────────────────────────────────────────────────────────
  &__card {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: #fff;
    border: 1px solid #f2f3f5;
    border-radius: 12px;
    box-shadow: 0 4px 8px rgba(0, 0, 0, 0.05);
    overflow: hidden;
  }

  // ── Card header ───────────────────────────────────────────────────────────
  &__card-header {
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: 56px;
    padding: 0 20px;
    border-bottom: 1px solid #e5e6eb;
  }

  &__card-title {
    font-size: 16px;
    font-weight: 500;
    color: #1d2129;
    text-transform: uppercase;
    letter-spacing: 0.5px;
  }

  // ── Status badge ─────────────────────────────────────────────────────────
  &__status-badge {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    height: 28px;
    padding: 0 12px;
    border: 1px solid;
    border-radius: 6px;

    &-dot {
      width: 8px;
      height: 8px;
      border-radius: 50%;
      flex-shrink: 0;
    }

    &-text {
      font-size: 14px;
    }
  }

  // ── Meta bar ──────────────────────────────────────────────────────────────
  &__meta-bar {
    flex-shrink: 0;
    display: flex;
    align-items: center;
    gap: 36px;
    padding: 12px 20px;
    background-color: #f7f8fa;
    border-bottom: 1px solid #e5e6eb;
  }

  &__meta-item {
    display: flex;
    align-items: center;
    gap: 8px;
  }

  &__meta-label {
    font-size: 13px;
    color: #86909c;
    white-space: nowrap;
  }

  &__meta-value {
    font-size: 14px;
    font-weight: 500;
    color: #1d2129;
    white-space: nowrap;
  }

  // ── Three-column body: sidebar + main + aside ─────────────────────────────
  &__body {
    flex: 1;
    min-height: 0;
    display: flex;
    overflow: hidden;
  }

  // ── Sidebar ───────────────────────────────────────────────────────────────
  &__sidebar {
    width: 200px;
    flex-shrink: 0;
    border-right: 1px solid #e5e6eb;
    overflow-y: auto;
    padding: 12px 0 20px;
    background-color: #fff;
  }

  // Top-level clickable nav item (Around the Building)
  &__nav-item {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 14px;
    font-size: 13px;
    font-weight: 500;
    color: #4e5969;
    cursor: pointer;
    position: relative;
    user-select: none;
    transition:
      background-color 0.15s,
      color 0.15s;

    &:hover:not(&--active) {
      background-color: #f7f8fa;
      color: #1d2129;
    }

    &--active {
      color: #30647f;
      background-color: #f0f7fb;

      &::before {
        content: '';
        position: absolute;
        left: 0;
        top: 0;
        bottom: 0;
        width: 3px;
        background-color: #30647f;
        border-radius: 0 2px 2px 0;
      }
    }
  }

  // Clickable group header (Inside the Building, Parking)
  &__nav-group-header {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 14px;
    font-size: 13px;
    font-weight: 500;
    color: #4e5969;
    margin-top: 4px;
    cursor: pointer;
    user-select: none;
    transition:
      background-color 0.15s,
      color 0.15s;

    &:hover:not(&--active) {
      background-color: #f7f8fa;
      color: #1d2129;
    }

    &--active {
      color: #30647f;
    }
  }

  // Child nav item (floors, P1/P2/P3)
  &__nav-child {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 6px 14px 6px 28px;
    font-size: 13px;
    font-weight: 400;
    color: #4e5969;
    cursor: pointer;
    position: relative;
    user-select: none;
    transition:
      background-color 0.15s,
      color 0.15s;

    &:hover:not(&--active) {
      background-color: #f7f8fa;
      color: #1d2129;
    }

    &--active {
      color: #30647f;
      background-color: #f0f7fb;
      font-weight: 500;

      &::before {
        content: '';
        position: absolute;
        left: 0;
        top: 0;
        bottom: 0;
        width: 3px;
        background-color: #30647f;
      }
    }
  }

  &__nav-label {
    flex: 1;
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  // Filled dot for parent-level items
  &__nav-dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background-color: #c9cdd4;
    flex-shrink: 0;

    &--active {
      background-color: #30647f;
    }
  }

  // Hollow dot for child items
  &__nav-child-dot {
    width: 6px;
    height: 6px;
    border-radius: 50%;
    border: 1.5px solid #c9cdd4;
    background: transparent;
    flex-shrink: 0;

    &--active {
      border-color: #30647f;
      background-color: #30647f;
    }
  }

  // Finding count badge in sidebar
  &__nav-badge {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 20px;
    height: 18px;
    padding: 0 5px;
    border-radius: 4px;
    background-color: #ffeae8;
    color: #f5626c;
    font-size: 11px;
    font-weight: 500;
    line-height: 1;
    flex-shrink: 0;
  }

  // ── Main content area ─────────────────────────────────────────────────────
  &__main {
    flex: 1;
    overflow-y: auto;
    padding: 24px 28px;
    display: flex;
    flex-direction: column;
    gap: 20px;
  }

  &__content-title {
    font-size: 26px;
    font-weight: 500;
    color: #1d2129;
    line-height: 1.3;
    flex-shrink: 0;
  }

  // ── Section cards ─────────────────────────────────────────────────────────
  &__sections {
    display: flex;
    flex-direction: column;
    gap: 12px;
  }

  &__section {
    border: 1px solid #e5e6eb;
    border-radius: 8px;
    overflow: hidden;

    &-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      min-height: 68px;
      padding: 12px 20px;
      background: #f7f8fa;
      cursor: pointer;
      user-select: none;
      transition: background-color 0.15s;

      &:hover {
        background-color: #f0f1f2;
      }

      &--open {
        border-bottom: 1px solid #e5e6eb;
      }

      .arco-icon {
        font-size: 16px;
        color: #1d2129;
        flex-shrink: 0;
      }
    }

    &-no {
      font-size: 12px;
      font-weight: 500;
      color: #30647f;
      text-transform: uppercase;
      letter-spacing: 0.3px;
      line-height: 22px;
      margin-bottom: 2px;
    }

    &-title {
      font-size: 18px;
      font-weight: 500;
      color: #1d2129;
      text-transform: uppercase;
      letter-spacing: 0.8px;
      line-height: 1.2;
    }

    &-body {
      padding: 0 20px;
      background: #fff;
    }
  }

  // ── Question items ────────────────────────────────────────────────────────
  &__item {
    padding: 20px 0;
    border-bottom: 1px solid #e5e6eb;

    &:last-child {
      border-bottom: none;
    }
  }

  &__item-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 16px;
  }

  &__item-question {
    flex: 1;
    min-width: 0;
    font-size: 16px;
    font-weight: 500;
    color: #1d2129;
    line-height: 1.4;
  }

  // ── Yes / No answer badge ─────────────────────────────────────────────────
  &__answer-badge {
    flex-shrink: 0;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 64px;
    height: 28px;
    border-radius: 4px;
    color: #fff;
    font-size: 14px;
    font-weight: 500;

    &--yes {
      background: linear-gradient(to top, #30647f, #4a8099);
    }

    &--no {
      background: linear-gradient(to top, #cb3d4b, #f5626c);
    }
  }

  // ── Findings container ────────────────────────────────────────────────────
  &__findings {
    margin-top: 12px;
    background: #f7f8fa;
    border-radius: 8px;
    padding: 0 12px;
  }

  // ── Individual finding ────────────────────────────────────────────────────
  &__finding {
    padding: 16px 0;
    border-bottom: 1px solid #e5e6eb;
    display: flex;
    flex-direction: column;
    gap: 12px;

    &:last-child {
      border-bottom: none;
    }
  }

  &__finding-title {
    font-size: 15px;
    font-weight: 500;
    color: #1d2129;
    text-transform: uppercase;
  }

  &__finding-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 12px;
  }

  // ── Field label / value ───────────────────────────────────────────────────
  &__field {
    display: flex;
    flex-direction: column;
    gap: 4px;
  }

  &__field-label {
    font-size: 12px;
    color: #86909c;
    line-height: 22px;
  }

  &__field-value {
    font-size: 14px;
    color: #1d2129;
    line-height: 1.6;
  }

  // ── Attachments ───────────────────────────────────────────────────────────
  &__attachments {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
  }

  &__attachment-img {
    border-radius: 6px;
    overflow: hidden;
    border: 1px solid #e5e6eb;

    .arco-image-img {
      object-fit: cover;
    }
  }

  &__attachment-placeholder {
    width: 72px;
    height: 72px;
    border-radius: 6px;
    background: #e5e6eb;
    border: 1px solid #d0d0d0;
  }

  // ── Footer buttons ────────────────────────────────────────────────────────
  &__footer {
    flex-shrink: 0;
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 16px 20px;
    border-top: 1px solid #e5e6eb;
    background: #fff;
    justify-content: end;
  }

  // ── Right aside: approval panel ───────────────────────────────────────────
  &__aside {
    width: 320px;
    flex-shrink: 0;
    display: flex;
    flex-direction: column;
    border-left: 1px solid #e5e6eb;
    overflow: hidden;

    .approval-progress-card {
      flex: 1;
      min-height: 0;
      display: flex;
      flex-direction: column;

      &__content {
        flex: 1;
        overflow-y: auto;
      }
    }
  }
}

